import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum UserRole {
  ADMIN = 'ADMIN',
  SERVEUR = 'SERVEUR',
  CAISSIER = 'CAISSIER'
}

export enum TableStatus {
  LIBRE = 'LIBRE',
  OCCUPEE = 'OCCUPEE',
  ATTENTE_PAIEMENT = 'ATTENTE_PAIEMENT'
}

export enum OrderStatus {
  EN_COURS = 'EN_COURS',
  SERVI = 'SERVI',
  PAYE = 'PAYE'
}

export enum PaymentMode {
  CASH_USD = 'CASH_USD',
  CASH_CDF = 'CASH_CDF',
  M_PESA = 'M_PESA',
  AIRTEL_MONEY = 'AIRTEL_MONEY',
  ORANGE_MONEY = 'ORANGE_MONEY'
}

export enum StockMovementType {
  ENTREE = 'ENTREE',
  VENTE = 'VENTE',
  PERTE = 'PERTE'
}

export interface User {
  id: string;
  nom: string;
  telephone: string;
  role: UserRole;
}

export interface Table {
  id: string;
  numero: number;
  statut: TableStatus;
}

export interface Product {
  id: string;
  nom: string;
  categorie: 'Bière' | 'Sucré' | 'Forte' | 'Cuisine';
  prixUSD: number;
  stockActuel: number;
  seuilAlerte: number;
  besoinVidange: boolean; // Si le produit nécessite une bouteille consignée
}

export interface OrderItem {
  productId: string;
  quantite: number;
  prixUnitaireUSD: number;
}

export interface Order {
  id: string;
  tableId: string;
  serveurId: string;
  items: OrderItem[];
  statut: OrderStatus;
  modePaiement?: PaymentMode;
  transactionId?: string;
  createdAt: number;
  vidangesDues: number; // Nombre de bouteilles vides non encore rendues
}

export interface Settings {
  tauxUSD_CDF: number;
  taxeDGRK: number; // Pourcentage
}

import { Product, Table, TableStatus } from './types';

export const INITIAL_TABLES: Table[] = Array.from({ length: 20 }, (_, i) => ({
  id: `table-${i + 1}`,
  numero: i + 1,
  statut: TableStatus.LIBRE,
}));

export const INITIAL_PRODUCTS: Product[] = [
  { id: '1', nom: 'Primus 72cl', categorie: 'Bière', prixUSD: 2.5, stockActuel: 48, seuilAlerte: 12, besoinVidange: true },
  { id: '2', nom: 'Tembo 33cl', categorie: 'Bière', prixUSD: 1.8, stockActuel: 24, seuilAlerte: 10, besoinVidange: true },
  { id: '3', nom: 'Coca-Cola 30cl', categorie: 'Sucré', prixUSD: 1.0, stockActuel: 60, seuilAlerte: 15, besoinVidange: true },
  { id: '4', nom: 'Eau Vive 1.5L', categorie: 'Sucré', prixUSD: 1.2, stockActuel: 30, seuilAlerte: 5, besoinVidange: false },
  { id: '5', nom: 'Poulet Mayo', categorie: 'Cuisine', prixUSD: 15, stockActuel: 10, seuilAlerte: 2, besoinVidange: false },
  { id: '6', nom: 'Frites', categorie: 'Cuisine', prixUSD: 5, stockActuel: 20, seuilAlerte: 5, besoinVidange: false },
  { id: '7', nom: 'Johnny Walker Black', categorie: 'Forte', prixUSD: 85, stockActuel: 5, seuilAlerte: 1, besoinVidange: false },
];

import React, { useState, useEffect, useMemo } from 'react';
import { 
  User, UserRole, Table, TableStatus, Product, Order, Settings, 
  OrderStatus, PaymentMode 
} from './types';
import { INITIAL_TABLES, INITIAL_PRODUCTS } from './constants';
import Dashboard from './components/Dashboard';
import OrderModal from './components/OrderModal';
import AdminPanel from './components/AdminPanel';
import Login from './components/Login';
import { 
  LayoutDashboard, 
  Settings as SettingsIcon, 
  LogOut, 
  ShoppingBag,
  PackageCheck
} from 'lucide-react';

const App: React.FC = () => {
  // Authentication State
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [currentView, setCurrentView] = useState<'dashboard' | 'admin' | 'stock'>('dashboard');

  // Business State
  const [tables, setTables] = useState<Table[]>(() => {
    const saved = localStorage.getItem('tables');
    return saved ? JSON.parse(saved) : INITIAL_TABLES;
  });

  const [products, setProducts] = useState<Product[]>(() => {
    const saved = localStorage.getItem('products');
    return saved ? JSON.parse(saved) : INITIAL_PRODUCTS;
  });

  const [orders, setOrders] = useState<Order[]>(() => {
    const saved = localStorage.getItem('orders');
    return saved ? JSON.parse(saved) : [];
  });

  const [settings, setSettings] = useState<Settings>(() => {
    const saved = localStorage.getItem('settings');
    return saved ? JSON.parse(saved) : { tauxUSD_CDF: 2850, taxeDGRK: 16 };
  });

  const [selectedTable, setSelectedTable] = useState<Table | null>(null);

  // Persistence (Offline First simulation)
  useEffect(() => {
    localStorage.setItem('tables', JSON.stringify(tables));
    localStorage.setItem('products', JSON.stringify(products));
    localStorage.setItem('orders', JSON.stringify(orders));
    localStorage.setItem('settings', JSON.stringify(settings));
  }, [tables, products, orders, settings]);

  const handleUpdateTableStatus = (tableId: string, status: TableStatus) => {
    setTables(prev => prev.map(t => t.id === tableId ? { ...t, statut: status } : t));
  };

  const handlePlaceOrder = (tableId: string, items: { productId: string, quantite: number }[]) => {
    const table = tables.find(t => t.id === tableId);
    if (!table || !currentUser) return;

    const orderItems = items.map(item => {
      const p = products.find(prod => prod.id === item.productId);
      return {
        productId: item.productId,
        quantite: item.quantite,
        prixUnitaireUSD: p?.prixUSD || 0
      };
    });

    // Calculate vidanges
    const vidanges = items.reduce((acc, item) => {
      const p = products.find(prod => prod.id === item.productId);
      return acc + (p?.besoinVidange ? item.quantite : 0);
    }, 0);

    const newOrder: Order = {
      id: `ord-${Date.now()}`,
      tableId,
      serveurId: currentUser.id,
      items: orderItems,
      statut: OrderStatus.EN_COURS,
      createdAt: Date.now(),
      vidangesDues: vidanges
    };

    setOrders(prev => [...prev, newOrder]);
    handleUpdateTableStatus(tableId, TableStatus.OCCUPEE);

    // Decrease stock
    setProducts(prev => prev.map(p => {
      const item = items.find(i => i.productId === p.id);
      return item ? { ...p, stockActuel: Math.max(0, p.stockActuel - item.quantite) } : p;
    }));
  };

  const handlePayment = (orderId: string, mode: PaymentMode, txId?: string) => {
    const order = orders.find(o => o.id === orderId);
    if (!order) return;

    setOrders(prev => prev.map(o => o.id === orderId ? { ...o, statut: OrderStatus.PAYE, modePaiement: mode, transactionId: txId } : o));
    handleUpdateTableStatus(order.tableId, TableStatus.LIBRE);
  };

  if (!currentUser) {
    return <Login onLogin={setCurrentUser} />;
  }

  return (
    <div className="flex flex-col h-screen w-full bg-slate-950 max-w-md mx-auto relative overflow-hidden shadow-2xl border-x border-slate-800">
      {/* Header */}
      <header className="flex items-center justify-between p-4 bg-slate-900 border-b border-slate-800 shrink-0">
        <div className="flex flex-col">
          <h1 className="text-lg font-bold text-white tracking-tight">KinTerrasse</h1>
          <span className="text-xs text-slate-400 font-medium">{currentUser.role} : {currentUser.nom}</span>
        </div>
        <div className="flex items-center gap-3">
            <div className="text-right flex flex-col items-end">
                <span className="text-[10px] text-slate-500 uppercase font-bold">Taux du Jour</span>
                <span className="text-sm font-bold text-emerald-400">1$ = {settings.tauxUSD_CDF.toLocaleString()} FC</span>
            </div>
            <button 
                onClick={() => setCurrentUser(null)} 
                className="p-2 rounded-full bg-slate-800 hover:bg-red-500/20 text-slate-400 hover:text-red-400 transition-all"
            >
                <LogOut size={20} />
            </button>
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-1 overflow-y-auto p-4 pb-24">
        {currentView === 'dashboard' && (
          <Dashboard 
            tables={tables} 
            orders={orders}
            onTableClick={(t) => setSelectedTable(t)} 
          />
        )}
        {currentView === 'admin' && (
          <AdminPanel 
            settings={settings} 
            orders={orders}
            products={products}
            onUpdateSettings={setSettings}
            onUpdateProducts={setProducts}
            currentUser={currentUser}
          />
        )}
        {currentView === 'stock' && (
            <div className="space-y-4">
                <h2 className="text-xl font-bold mb-4">État du Stock</h2>
                <div className="grid gap-3">
                    {products.map(p => (
                        <div key={p.id} className={`p-4 rounded-xl bg-slate-900 border ${p.stockActuel <= p.seuilAlerte ? 'border-amber-500/50' : 'border-slate-800'}`}>
                            <div className="flex justify-between items-start mb-2">
                                <div>
                                    <h3 className="font-bold">{p.nom}</h3>
                                    <span className="text-xs text-slate-500">{p.categorie}</span>
                                </div>
                                <div className="text-right">
                                    <span className={`text-lg font-bold ${p.stockActuel <= p.seuilAlerte ? 'text-amber-500' : 'text-emerald-500'}`}>
                                        {p.stockActuel}
                                    </span>
                                    <span className="text-[10px] block text-slate-500 uppercase">Unités restantes</span>
                                </div>
                            </div>
                            <div className="w-full bg-slate-800 h-1.5 rounded-full overflow-hidden">
                                <div 
                                    className={`h-full transition-all duration-500 ${p.stockActuel <= p.seuilAlerte ? 'bg-amber-500' : 'bg-emerald-500'}`}
                                    style={{ width: `${Math.min(100, (p.stockActuel / 50) * 100)}%` }}
                                />
                            </div>
                        </div>
                    ))}
                </div>
            </div>
        )}
      </main>

      {/* Navigation */}
      <nav className="absolute bottom-0 left-0 right-0 p-4 bg-slate-900/80 backdrop-blur-md border-t border-slate-800 grid grid-cols-3 gap-2 shrink-0">
        <button 
          onClick={() => setCurrentView('dashboard')}
          className={`flex flex-col items-center justify-center p-2 rounded-xl transition-all ${currentView === 'dashboard' ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-500/20' : 'text-slate-400 hover:bg-slate-800'}`}
        >
          <LayoutDashboard size={20} />
          <span className="text-[10px] font-bold mt-1">Salles</span>
        </button>
        <button 
          onClick={() => setCurrentView('stock')}
          className={`flex flex-col items-center justify-center p-2 rounded-xl transition-all ${currentView === 'stock' ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-500/20' : 'text-slate-400 hover:bg-slate-800'}`}
        >
          <PackageCheck size={20} />
          <span className="text-[10px] font-bold mt-1">Stock</span>
        </button>
        <button 
          onClick={() => setCurrentView('admin')}
          className={`flex flex-col items-center justify-center p-2 rounded-xl transition-all ${currentView === 'admin' ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-500/20' : 'text-slate-400 hover:bg-slate-800'}`}
        >
          <SettingsIcon size={20} />
          <span className="text-[10px] font-bold mt-1">Admin</span>
        </button>
      </nav>

      {/* Modals */}
      {selectedTable && (
        <OrderModal 
          table={selectedTable}
          orders={orders.filter(o => o.tableId === selectedTable.id && o.statut !== OrderStatus.PAYE)}
          products={products}
          settings={settings}
          onClose={() => setSelectedTable(null)}
          onPlaceOrder={(items) => handlePlaceOrder(selectedTable.id, items)}
          onPayment={handlePayment}
          onUpdateTableStatus={handleUpdateTableStatus}
        />
      )}
    </div>
  );
};

export default App;

