import React, { useState, useMemo } from 'react';
import { 
  Table, Product, Order, Settings, TableStatus, OrderStatus, PaymentMode 
} from '../types';
import { X, Plus, Minus, CreditCard, Receipt, Trash2, Smartphone, DollarSign, Wallet } from 'lucide-react';

interface OrderModalProps {
  table: Table;
  orders: Order[];
  products: Product[];
  settings: Settings;
  onClose: () => void;
  onPlaceOrder: (items: { productId: string, quantite: number }[]) => void;
  onPayment: (orderId: string, mode: PaymentMode, txId?: string) => void;
  onUpdateTableStatus: (tableId: string, status: TableStatus) => void;
}

const OrderModal: React.FC<OrderModalProps> = ({ 
  table, orders, products, settings, onClose, onPlaceOrder, onPayment, onUpdateTableStatus 
}) => {
  const [view, setView] = useState<'menu' | 'bill' | 'pay'>('menu');
  const [cart, setCart] = useState<{ productId: string, quantite: number }[]>([]);
  const [paymentMode, setPaymentMode] = useState<PaymentMode | null>(null);
  const [transactionId, setTransactionId] = useState('');

  const activeOrder = orders[0]; // Simplified: 1 active order per table

  const cartTotal = useMemo(() => {
    return cart.reduce((acc, item) => {
      const p = products.find(prod => prod.id === item.productId);
      return acc + (p?.prixUSD || 0) * item.quantite;
    }, 0);
  }, [cart, products]);

  const billTotalUSD = useMemo(() => {
    if (!activeOrder) return 0;
    return activeOrder.items.reduce((acc, item) => acc + (item.prixUnitaireUSD * item.quantite), 0);
  }, [activeOrder]);

  const billTotalCDF = billTotalUSD * settings.tauxUSD_CDF;
  const taxeUSD = billTotalUSD * (settings.taxeDGRK / 100);
  const totalWithTaxeUSD = billTotalUSD + taxeUSD;

  const handleAddToCart = (pId: string) => {
    setCart(prev => {
      const existing = prev.find(i => i.productId === pId);
      if (existing) {
        return prev.map(i => i.productId === pId ? { ...i, quantite: i.quantite + 1 } : i);
      }
      return [...prev, { productId: pId, quantite: 1 }];
    });
  };

  const handleRemoveFromCart = (pId: string) => {
    setCart(prev => {
      const existing = prev.find(i => i.productId === pId);
      if (existing && existing.quantite > 1) {
        return prev.map(i => i.productId === pId ? { ...i, quantite: i.quantite - 1 } : i);
      }
      return prev.filter(i => i.productId !== pId);
    });
  };

  return (
    <div className="fixed inset-0 z-50 flex items-end justify-center bg-black/60 backdrop-blur-sm">
      <div className="w-full max-w-md bg-slate-900 rounded-t-[3rem] p-6 shadow-2xl flex flex-col max-h-[90vh] border-t border-slate-800">
        {/* Header */}
        <div className="flex justify-between items-center mb-6 px-2">
          <div>
            <h2 className="text-2xl font-black text-white">Table {table.numero}</h2>
            <p className="text-xs font-bold text-slate-500 uppercase tracking-widest">
              {activeOrder ? 'Commande Active' : 'Nouvelle Commande'}
            </p>
          </div>
          <button onClick={onClose} className="p-2 bg-slate-800 rounded-full text-slate-400">
            <X size={24} />
          </button>
        </div>

        {/* Tab switcher */}
        <div className="flex bg-slate-800/50 p-1.5 rounded-2xl mb-6">
            <button 
                onClick={() => setView('menu')}
                className={`flex-1 py-3 px-2 rounded-xl text-xs font-bold flex items-center justify-center gap-2 transition-all ${view === 'menu' ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-400'}`}
            >
                <Plus size={16} /> Menu
            </button>
            <button 
                onClick={() => setView('bill')}
                disabled={!activeOrder}
                className={`flex-1 py-3 px-2 rounded-xl text-xs font-bold flex items-center justify-center gap-2 transition-all ${view === 'bill' ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-400 disabled:opacity-30'}`}
            >
                <Receipt size={16} /> Facture
            </button>
        </div>

        {/* Views */}
        <div className="flex-1 overflow-y-auto min-h-0 space-y-4 px-1">
          {view === 'menu' && (
            <div className="space-y-6">
              {/* Products by category */}
              {['Bière', 'Sucré', 'Forte', 'Cuisine'].map(cat => (
                <div key={cat}>
                  <h3 className="text-[10px] font-black uppercase text-slate-500 mb-3 tracking-[0.2em]">{cat}</h3>
                  <div className="grid gap-3">
                    {products.filter(p => p.categorie === cat).map(p => (
                      <div key={p.id} className="flex items-center bg-slate-800/40 p-3 rounded-2xl border border-slate-800">
                        <div className="flex-1">
                          <h4 className="font-bold text-slate-100">{p.nom}</h4>
                          <div className="flex items-baseline gap-2 mt-0.5">
                            <span className="text-sm font-bold text-emerald-500">${p.prixUSD.toFixed(2)}</span>
                            <span className="text-[10px] font-medium text-slate-500">{(p.prixUSD * settings.tauxUSD_CDF).toLocaleString()} FC</span>
                          </div>
                        </div>
                        <div className="flex items-center gap-3">
                            <button onClick={() => handleRemoveFromCart(p.id)} className="w-8 h-8 flex items-center justify-center rounded-xl bg-slate-700 text-slate-300">
                                <Minus size={16} />
                            </button>
                            <span className="font-bold w-4 text-center">{cart.find(i => i.productId === p.id)?.quantite || 0}</span>
                            <button onClick={() => handleAddToCart(p.id)} className="w-8 h-8 flex items-center justify-center rounded-xl bg-indigo-600 text-white shadow-md">
                                <Plus size={16} />
                            </button>
                        </div>
                      </div>
                    ))}
                  </div>
                </div>
              ))}
            </div>
          )}

          {view === 'bill' && activeOrder && (
            <div className="space-y-6">
               <div className="bg-slate-800/40 rounded-3xl p-6 border border-slate-800">
                    <div className="space-y-3 mb-6">
                        {activeOrder.items.map((item, idx) => {
                            const p = products.find(prod => prod.id === item.productId);
                            return (
                                <div key={idx} className="flex justify-between items-center text-sm">
                                    <span className="text-slate-400 font-medium">
