                    }}
                    disabled={cart.length === 0}
                    className="col-span-1 flex-1 p-4 rounded-2xl bg-indigo-600 text-white font-black text-lg shadow-xl shadow-indigo-500/20 disabled:opacity-50"
                >
                    Envoyer ({cartTotal.toFixed(2)}$)
                </button>
            </div>
          )}

          {view === 'bill' && (
             <button 
                onClick={() => setView('pay')}
                className="w-full p-5 rounded-2xl bg-emerald-600 text-white font-black text-xl shadow-xl shadow-emerald-500/20"
            >
                Encaisser Paiement
            </button>
          )}

          {view === 'pay' && (
             <div className="grid grid-cols-2 gap-4">
                <button 
                    onClick={() => setView('bill')}
                    className="p-4 rounded-2xl border-2 border-slate-700 text-slate-400 font-bold"
                >
                    Retour
                </button>
                <button 
                    onClick={() => {
                        if (paymentMode && activeOrder) {
                            onPayment(activeOrder.id, paymentMode, transactionId);
                            onClose();
                        }
                    }}
                    disabled={!paymentMode || (paymentMode.includes('MONEY') && !transactionId)}
                    className="p-4 rounded-2xl bg-emerald-600 text-white font-black shadow-xl shadow-emerald-500/20 disabled:opacity-50"
                >
                    Valider
                </button>
             </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default OrderModal;
